text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST 공개 릴리스 진행",
        "conditions": ["스모크 테스트 통과 필수"]
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "mismatch 발생 시 먼저 패키지 설정을 점검하고, 계약(컨트랙트) 자체가 잘못된 경우에만 스크립트 검토"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표(확정 릴리스 결정 아님)"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 목요일 검토",
        "note": "가능하면 진행 제안만 있었고, 담당자 미지정"
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로 오류",
        "impact": "릴리스 지연 가능"
      },
      {
        "risk": "README 설치 단계가 오래된 상태",
        "impact": "릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 포함할 것인가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 점검",
      "due": "미정(정확 시한 미설정)",
      "status": "선행조건 대기",
      "source_certainty": "confirmed_with_no_exact_deadline"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "목요일(가능 시)",
      "status": "담당자 미지정",
      "source_certainty": "suggested_unassigned"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun 스모크 테스트 결과(금요일 10:00 KST) 확인",
      "Doyun 트리아지 노트(action_items.md) 작성 여부(금요일 12:00 KST) 확인",
      "Hara의 tarball 경로 점검 결과 확인",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 내부 스트레치 목표 기재 여부 결정"
    ],
    "do_not_invent": [
      "고객/외부 파트너 정보",
      "예산 정보",
      "보안 사고 정보",
      "프로덕션 장애 정보",
      "법무 승인 필수 요건",
      "미지정 담당자/미합의 마감시한의 단정"
    ]
  },
  "non_invention_rules": [
    "회의 원문에 없는 고객명, 예산, 보안사고, 장애, 법무요건을 추가하지 않는다.",
    "명시되지 않은 오너와 데드라인은 '미정' 또는 '미지정'으로 기록한다.",
    "제안과 확정 결정을 구분하고, 거절된 제안은 별도 표기한다.",
    "내부 스트레치 목표와 대외 확정 일정은 혼합하지 않는다.",
    "오픈 질문은 답을 추정하지 않고 질문 상태로 유지한다."
  ]
}
